import{_ as a,o as e,c as t,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const S=JSON.parse('{"title":"天使","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/天使.md","filePath":"4.资源分区/1.血统与训练/1.生理类/天使.md"}'),s={name:"4.资源分区/1.血统与训练/1.生理类/天使.md"};function p(d,b,l,i,h,_){return e(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"天使",tabindex:"-1"},[n("天使 "),r("a",{class:"header-anchor",href:"#天使","aria-label":'Permalink to "天使"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),o('<h1 id="天使-1" tabindex="-1">天使 <a class="header-anchor" href="#天使-1" aria-label="Permalink to &quot;天使&quot;">​</a></h1><p>远古高山人族<br> 天使本义指上帝的使者，来自天上的使者。大多数宗教信仰中都有类似概念。<br> 基督徒一般译为天使；穆斯林有时译为天仙。<br> 代表圣洁、良善，正直，上帝（安拉）旨意的传达者、<br> 为上帝（安拉）服役的灵、受上帝（安拉）差遣保护信众不被恶魔侵扰的保护者<br> 。将神给人的讯息带进人间的桥梁。人间监察者、<br> 人们行为(包括隐秘)的忠实的记录者，对抗神国敌人的战士、<br> 神国内拥有特殊职业的人民，然而真正的过去往往被神的辉光掩埋<br> 圣洁之后的真实亦同埋藏于血脉之中<br> 本血统以及所有能力皆作为魔幻本质，但是特殊的，当本血统升到B级开始<br> 更改为自然本质进行购买，在这种情况下，本血统更名名为远古高山人族，并且光明生物<br> 特质失效或者更换为【黑暗生物】</p><p>“灵”D+600<br> 【虽然天使能够以人的身形显现（创十八3），<br> 但天使称为“灵”（来一14）】<br> 在该阶段下你视为第一天（Shiamaim）中的天使，<br> 由加百列掌管。驻守此地的天使群也负责管理星星、气象等等。<br> （月球是最接近尘世的天界，信仰不坚者的居住地。）<br> “灵”：已经成为了新生天使的你获得了天使之躯的改造，这代表你能够目视世间所存在的更多非实质的灵性生物（灵感视觉）<br> 并且经过初步洗练的身躯获得了对于更强的抗性，你的天生防御获得了【防能量】特性，你成为了【光明生物】。<br> 第一天：身为天使的你获得了身为世间运行的管理者初步的权力，虽然还能稚嫩，但是<br> 你拥有了推动天象变更的能力，经过一个小时的引导，在这个阶段弱小的你还只能够做到将雨略微增加或者减小，将盈月变成满月<br> 将乌云略微散开类似程度的事情，这视为D命运来源的能力</p><p>“赞美诗”C+1200<br> 天使都是被创造的：《诗篇》呼唤大自然，赞美神的创造。<br> 耶和华用他的话创造了这些天上的灵体（诗一四八2至5）。<br> 约伯受到提醒，天使受造时，曾向神赞美歌唱（伯三十八6至7）。<br> 基督创造了至终要向他献上赞美诗的天使（西一16）。<br> 第二天，称为Akira，大天使拉斐尔的领地、部分受惩天使的禁闭所亦设于此。<br> （水星天：第二重天，力行善事者，死后灵魂居于此。）<br> 赞美诗：身为耶和华最伟大的造物，从这个阶段开始你有了职位的划分，在下列三种职业中选择一种，每个<br> 剧本之后获得一次切换职权的机会<br> 权天使：你拥有了宣唱唯一全知全能之主的权能，在这个阶段下你可以选定一个社交技能和专业（在购买时指定）代替专注意志进行豁免或检定，无礼之徒无颜拜会圣洁之意<br> 力天使：在这个阶段你获得了操控圣洁之力的能力，成为御使主之光辉的使者，<br> 当你进行近战武器攻击的时候，可以选择将攻击伤害转化为对生理属性的属性伤害（在购买时选定），强韧豁免。无知之徒无力拜会恩赐的光辉<br> 智天使：领会主之智确的你获得了一定程度上倒流过去的能力，你现在在触摸一个物品时，可以花费移动动作来观测到其过去至多一个小时所经历的影像，这视为你操控身为世间管理者的权限对世界本身进行宣言。这是一个C级命运来源的回溯效果。</p><p>“被创造者”B+2400<br> 第三天，Sagoon或Shehkim，支配天使为权天使Angel。<br> 在伊斯兰教中， 死亡天使Azrael领有此一天界。<br> （金星天：多情者的灵魂居所。<br> 天使同时被造，而且数目众多：《歌罗西书》一章16节提到创造，<br> 指出天使的被造是一次性的行动。天使的创造不是延续性的。<br> 因为天使不能生育（太二十二30），因而天使的数目也是固定的。<br> ......<br> ......<br> ...<br> 我们......是......一次性的.........吗？<br> 权与死亡：你无需再进行C级的选定，在这个阶段的你拥有了足够的容器同时<br> 储存三种权能与一身，并且在这个阶段，你正式获得了身为天使的强大羽翼具有了等于移动速度的完美飞行能力<br> “思考”：身为一个天使到达了成熟体的你在某个偶然之下对自己的存在产生了<br> 莫名的疑惑，这种令你产生了亵渎的想法在你的脑海之中久久回荡，但是身为<br> 主的使徒你越告诉自己不应该去回想，心中的某颗种子却开始生根发芽<br> 你获得了B级的心灵免疫和B级幻象免疫<br> 并且获得了1点生效与回复异常状态的治疗，具有医疗点24可以治愈每一档异常。</p><p>启明星 A+4800<br> 第四天，Zeble或Mahanon，还有数种不同称呼，<br> 由大天使米迦勒支配。启示录中所记载的天上耶路撒冷城<br> ，便坐落于太阳天，以诺书亦声称生命之树长在太阳天的义人之园中。<br> （太阳天：智者与圣者被安置于此重天。）<br> 天使的等级比人高：人类都是“比天使微小一点”（来二7）。<br> 天使不会受到人所受的限制，<br> 因为天使是不会死亡的（路二十36）。<br> 天使比人更有智慧（撒下十四20），<br> 但其智慧也是有限的（太二十四36）。<br> 天使比人更有能力（太二十八2；徒五19；彼后二11），<br> 但天使的能力也是有限的（但十13）<br> 天使的....<br> 够了。<br> 无需这些<br> 祂说<br> 启明星：世界逐渐在你的眼前真正清晰起来，与此同时之下你的能力居然在赐予的<br> 圣力之外独立开始变强，你似乎明白了什么，即使你的位格猛然徒增，一重天的<br> 支配者与你互称平级，但位阶迁跃的同时，你的眼瞳第一次望向了真正的天空。<br> 在这个阶段下你的力量相较正常天使开始产生了质的飞跃，你获得了S级的心灵免疫<br> 和S级的幻象免疫（取代B级的两种免疫效果）。<br> 身为高位天使的你能力获得了飞跃的提升举手投足都携带着真正的神罚，<br> 你在赞美诗阶段选择的属性伤害效果，在这个阶段成为了常态能力，<br> 你的近战攻击从转化为选定的属性伤害改为附带选定的属性伤害异常。<br> 并且你获得了对天象极大程度操控的能力，进行一小时的引导，你能够自由的操控<br> 月亮的大致盈满或者天气的好坏，但依旧需要在一定的原先基础上进行改变。<br> （比如你可以操控雨的大小，但是无法制造逆季节的天气或者在沙漠强行落雪，在冰原制造高温）<br> 天之近从：已经隐隐抵达天使之位顶点的你某种意义上成为了主手中最得力的<br> 工具，这也使得你出行执行任务的时候可以指示世界引导出符合你需求的合适<br> 身份，这视为A级命运来源的背景身份能力，但限定为宗教类身份。</p><p>于废墟升起的星之光辉 S+9600<br> 第五天，Mahon，此天之北部为荒凉废墟，设有天使的牢——<br> 第六天，Zebel，天使学习智识的所在——<br> 第七天，Arabot，███████<br> 第【】天，你来到了“祂”之前，如你想的一样。<br> 这里只有荒凉的废墟，残破的王座，失落的林，徘徊的梦<br> 和如你一般的面孔。<br> 十字的处刑架上，琥珀般黄金的血液流入下界，一切的故事将重新起源<br> 你站立在那最可笑的座之前，如同镜子一般，流露出于面前的存在一样的表情。<br> “他”：你寻回了自己的起源，从现在开始不论原先如何，你自如选择自己为【光明生物】/【黑暗生物】/或二者都不是，<br> 当你处于【光明生物】时，你的名字可视为路西菲尔，当你处于【黑暗生物】时，你的名字可视为路西法。<br> 当你名为路西菲尔时，你的社交检定获得【传奇】特性，任何生灵都该当专注聆听神之侧的宣言。<br> 当你名为路西法时，对你所击败的但却未死的单位（无助状态）或者自愿接受的存在使用，该生物将受到来自你的S级支配效果<br> “她”：你成为了真正的神之侧席，无任何存在知晓你到底有没有步入那残破的<br> 荒谬神座之上，但是唯有你清楚，在那一天，你到底得到了什么，成为了什么。<br> 你进入世界时自带的背景身份升级为S级，这视为一位真正的伟大存在进行驾临，但是相反的，你冥冥之中主动拒绝任何宗教类相关的身份<br> 你真正拥有了操控回顾真正历史的能力，那是追溯到久远久远久远，久远至时光本身为止枯竭的过去<br> 即使在不同的世界有所失真，但你依旧获得了S级信息回溯的能力，花费十五分钟进行引导，你可以倒流目光范围内的过去并事无巨细的回放在脑海<br> “祂”：在追寻一切的道路之上你的位格不断的拔高，至今你已无力回到原本弱小而真正的自己<br> 但是相对的，神力的虚影使得你免疫物理伤害，并且在死亡之后，你强大的神魂将脱离<br> 当前不足以完全承载你降临的身躯，以灵体的方式存在，灵体状态中你具有等于生命值<br> 的结构值，并且在24小时之后，以完整的状态复活，这视为一个S级命运来源的复活效果。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(s,[["render",p]]);export{S as __pageData,m as default};
